 1	import type { FC } from 'react';
 2	
 3	import { Icon, Label, Tooltip } from '@patternfly/react-core';
 4	import { ExclamationTriangleIcon } from '@patternfly/react-icons';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	import { getRootDiskLabelByKey, isNotFirstKeyOrRootFilesystem } from '../utils/utils';
 8	
 9	type DiskLabelProps = {
10	  diskKey: string | undefined;
11	};
12	
13	const DiskLabel: FC<DiskLabelProps> = ({ diskKey }) => {
14	  const { t } = useForkliftTranslation();
15	  const diskLabel = getRootDiskLabelByKey(diskKey);
16	
17	  return (
18	    <Label
19	      isCompact
20	      color="grey"
21	      icon={
22	        isNotFirstKeyOrRootFilesystem(diskKey) && (
23	          <Tooltip
24	            content={t(
25	              'Root filesystem format should start with "/dev/sd[X]", see documentation for more information.',
26	            )}
27	          >
28	            <Icon className="pf-v6-u-mr-xs">
29	              <ExclamationTriangleIcon color="#F0AB00" />
30	            </Icon>
31	          </Tooltip>
32	        )
33	      }
34	    >
35	      {diskLabel}
36	    </Label>
37	  );
38	};
39	
40	export default DiskLabel;

